class Game:
    def make_move(self, move):
        from_coord, to_coord = move.split('-')
        start_x, start_y = int(from_coord[1]) - 1, ord(from_coord[0]) - 97
        end_x, end_y = int(to_coord[1]) - 1, ord(to_coord[0]) - 97

        piece = self.board.state[start_x][start_y]
        if not piece:
            return False

        if (end_x + end_y) % 2 == 1 or start_x == end_x:
            return False

        # Simple move logic
        if abs(end_x - start_x) == 1 and abs(end_y - start_y) == 1:
            self.board.state[end_x][end_y] = piece
            self.board.state[start_x][start_y] = None
            return True

        # Capture logic
        if abs(end_x - start_x) == 2 and abs(end_y - start_y) == 2:
            intermediate_x, intermediate_y = (start_x + end_x) // 2, (start_y + end_y) // 2
            captured_piece = self.board.state[intermediate_x][intermediate_y]
            if captured_piece and captured_piece.color != piece.color:
                self.board.state[end_x][end_y] = piece
                self.board.state[start_x][start_y] = None
                self.board.state[intermediate_x][intermediate_y] = None
                return True

        return False
